// ---- Error Handling in Network Calls ----

// ---- Sealed class for API results ----
sealed class ApiResult<out T> {
    data class Success<T>(val data: T) : ApiResult<T>()
    data class Error(val message: String, val code: Int? = null) : ApiResult<Nothing>()
    object Loading : ApiResult<Nothing>()
}

// ---- Retrofit with error handling ----
interface ErrorHandlingApi {
    @GET("posts")
    suspend fun getPosts(): List<Post>

    @GET("posts/{id}")
    suspend fun getPost(@Path("id") id: Int): Post
}

// ---- Repository with error handling ----
class SafeApiRepository {
    private val api = RetrofitClient.api

    suspend fun getPosts(): ApiResult<List<Post>> {
        return try {
            val posts = api.getPosts()
            ApiResult.Success(posts)
        } catch (e: IOException) {
            ApiResult.Error("Network error: ${e.message}", 0)
        } catch (e: HttpException) {
            ApiResult.Error("Server error: ${e.message}", e.code())
        } catch (e: Exception) {
            ApiResult.Error("Unknown error: ${e.message}")
        }
    }

    suspend fun getPost(id: Int): ApiResult<Post> {
        return try {
            val post = api.getPost(id)
            ApiResult.Success(post)
        } catch (e: IOException) {
            ApiResult.Error("Network error: ${e.message}", 0)
        } catch (e: HttpException) {
            when (e.code()) {
                404 -> ApiResult.Error("Post not found", 404)
                500 -> ApiResult.Error("Server error", 500)
                else -> ApiResult.Error("Error: ${e.message}", e.code())
            }
        } catch (e: Exception) {
            ApiResult.Error("Unknown error: ${e.message}")
        }
    }
}

// ---- ViewModel with error handling ----
class ErrorHandlingViewModel : ViewModel() {
    private val repository = SafeApiRepository()

    private val _posts = MutableStateFlow<ApiResult<List<Post>>>(ApiResult.Loading)
    val posts: StateFlow<ApiResult<List<Post>>> = _posts.asStateFlow()

    private val _post = MutableStateFlow<ApiResult<Post>>(ApiResult.Loading)
    val post: StateFlow<ApiResult<Post>> = _post.asStateFlow()

    fun loadPosts() {
        viewModelScope.launch {
            _posts.value = ApiResult.Loading
            val result = repository.getPosts()
            _posts.value = result
        }
    }

    fun loadPost(id: Int) {
        viewModelScope.launch {
            _post.value = ApiResult.Loading
            val result = repository.getPost(id)
            _post.value = result
        }
    }

    fun retryLoadPosts() {
        loadPosts()
    }

    fun retryLoadPost(id: Int) {
        loadPost(id)
    }
}

// ---- UI with error handling ----
@Composable
fun ErrorHandlingScreen() {
    val viewModel: ErrorHandlingViewModel = viewModel()
    val postsResult by viewModel.posts.collectAsState()
    val postResult by viewModel.post.collectAsState()

    var selectedPostId by remember { mutableStateOf(0) }

    Scaffold(
        topBar = { TopAppBar { Text("Error Handling Demo") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // ---- Post result (single) ----
            when (postResult) {
                is ApiResult.Loading -> {
                    Box(
                        modifier = Modifier.fillMaxWidth().height(80.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        CircularProgressIndicator()
                    }
                }
                is ApiResult.Success -> {
                    val post = (postResult as ApiResult.Success).data
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.primaryContainer
                        )
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            Text("✅ Post loaded:", style = MaterialTheme.typography.titleMedium)
                            Text(post.title, style = MaterialTheme.typography.titleLarge)
                            Text(post.body)
                        }
                    }
                }
                is ApiResult.Error -> {
                    val error = (postResult as ApiResult.Error)
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.errorContainer
                        )
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            Text(
                                text = "❌ ${error.message}",
                                color = MaterialTheme.colorScheme.onErrorContainer,
                                style = MaterialTheme.typography.titleMedium
                            )
                            if (error.code != null) {
                                Text(
                                    text = "Code: ${error.code}",
                                    color = MaterialTheme.colorScheme.onErrorContainer
                                )
                            }
                            Button(
                                onClick = { viewModel.retryLoadPost(selectedPostId) }
                            ) {
                                Text("Retry")
                            }
                        }
                    }
                }
            }

            // ---- Posts list ----
            when (postsResult) {
                is ApiResult.Loading -> {
                    Box(
                        modifier = Modifier.fillMaxWidth().height(100.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        CircularProgressIndicator()
                    }
                }
                is ApiResult.Success -> {
                    val posts = (postsResult as ApiResult.Success).data
                    LazyColumn(
                        verticalArrangement = Arrangement.spacedBy(8.dp),
                        modifier = Modifier.weight(1f)
                    ) {
                        items(posts) { post ->
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clickable {
                                        selectedPostId = post.id
                                        viewModel.loadPost(post.id)
                                    },
                                elevation = CardDefaults.cardElevation(2.dp)
                            ) {
                                Column(modifier = Modifier.padding(16.dp)) {
                                    Text(post.title, style = MaterialTheme.typography.titleMedium)
                                    Text("ID: ${post.id}", style = MaterialTheme.typography.bodySmall)
                                }
                            }
                        }
                    }
                }
                is ApiResult.Error -> {
                    val error = (postsResult as ApiResult.Error)
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.errorContainer
                        )
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            Text(
                                text = "❌ ${error.message}",
                                color = MaterialTheme.colorScheme.onErrorContainer,
                                style = MaterialTheme.typography.titleMedium
                            )
                            Button(
                                onClick = { viewModel.retryLoadPosts() }
                            ) {
                                Text("Retry")
                            }
                        }
                    }
                }
            }

            // ---- Buttons ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Button(
                    onClick = { viewModel.loadPosts() },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("Load Posts")
                }

                Button(
                    onClick = { viewModel.loadPost(99) },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("Test 404")
                }
            }
        }
    }
}

