package com.example.errorhandling

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

sealed class ApiResult<out T> {
    data class Success<T>(val data: T) : ApiResult<T>()
    data class Error(val message: String) : ApiResult<Nothing>()
    object Loading : ApiResult<Nothing>()
}

class ApiViewModel : ViewModel() {
    private val _result = MutableStateFlow<ApiResult<String>>(ApiResult.Loading)
    val result: StateFlow<ApiResult<String>> = _result.asStateFlow()

    fun fetchData(shouldFail: Boolean = false) {
        viewModelScope.launch {
            _result.value = ApiResult.Loading
            delay(1000)
            try {
                if (shouldFail) {
                    throw Exception("Network error: Failed to fetch data")
                }
                _result.value = ApiResult.Success("Data loaded successfully!")
            } catch (e: Exception) {
                _result.value = ApiResult.Error(e.message ?: "Unknown error")
            }
        }
    }
}

@Composable
fun ErrorHandlingApp() {
    val viewModel: ApiViewModel = viewModel()
    val result by viewModel.result.collectAsState()

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        when (result) {
            is ApiResult.Loading -> {
                CircularProgressIndicator()
                Text("Loading...")
            }
            is ApiResult.Success -> {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.primaryContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text("✅ ${(result as ApiResult.Success).data}")
                    }
                }
            }
            is ApiResult.Error -> {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(
                            text = "❌ ${(result as ApiResult.Error).message}",
                            color = MaterialTheme.colorScheme.onErrorContainer
                        )
                        Button(
                            onClick = { viewModel.fetchData(false) },
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Text("Retry")
                        }
                    }
                }
            }
        }

        Button(
            onClick = { viewModel.fetchData(false) },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Fetch Data")
        }

        Button(
            onClick = { viewModel.fetchData(true) },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Fetch with Error")
        }
    }
}
